class TestScreenPhysicalDpi:
    def test_normal_96dpi(self):
        root = _mock_root(screen_px=1920, screen_mm=508)  # ~96 DPI
        dpi = _screen_physical_dpi(root)
        assert dpi is not None
        assert abs(dpi - 96.0) < 1.0

    def test_hidpi_192dpi(self):
        root = _mock_root(screen_px=3840, screen_mm=508)  # ~192 DPI
        dpi = _screen_physical_dpi(root)
        assert dpi is not None
        assert abs(dpi - 192.0) < 1.0

    def test_zero_mm_returns_none(self):
        root = _mock_root(screen_mm=0)
        assert _screen_physical_dpi(root) is None

    def test_exception_returns_none(self):
        root = MagicMock()
        root.winfo_screenmmwidth.side_effect = RuntimeError("no display")
        assert _screen_physical_dpi(root) is None


